class NumArray {
    vector<long long> pre;
public:
    NumArray(vector<int>& nums) {
        pre.push_back(0);
        for (int x : nums) pre.push_back(pre.back() + x);
    }
    int sumRange(int left, int right) {
        return pre[right + 1] - pre[left];
    }
};

