typedef struct {
    long long* pre;
    int n;
} NumArray;
NumArray* numArrayCreate(int* nums, int n) {
    NumArray* obj = malloc(sizeof(NumArray));
    obj->n = n;
    obj->pre = malloc((n + 1) * sizeof(long long));
    obj->pre[0] = 0;
    for (int i = 0; i < n; i++) obj->pre[i + 1] = obj->pre[i] + nums[i];
    return obj;
}
int numArraySumRange(NumArray* obj, int left, int right) {
    return (int)(obj->pre[right + 1] - obj->pre[left]);
}
